+        let e = RerankError::EmptyInput;
+        assert_eq!(e.to_string(), "empty input to reranker");
+    }
+
+    #[test]
+    fn rerank_error_debug() {
+        let e = RerankError::ModelError("fail".into());
+        let dbg = format!("{e:?}");
