+    #[test]
+    fn scored_doc_clone_preserves_all_fields() {
+        let doc = ScoredDoc {
+            id: 999,
+            text: "long text content here".into(),
+            score: 0.12345,
+        };
+        let doc2 = doc.clone();
+        assert_eq!(doc2.id, 999);
