+        let results = idx.search(&[1.0, 0.0], 0);
+        assert!(results.is_empty());
+    }
+
+    #[test]
+    fn search_k_exceeds_count() {
+        let vecs = vec![
+            (1u64, vec![1.0, 0.0]),
+            (2, vec![0.0, 1.0]),
+        ];
+        let idx = make_index(&vecs);
+        let results = idx.search(&[1.0, 0.0], 100);
