+    #[test]
+    fn search_ordering_by_similarity() {
+        let vecs = vec![
+            (1u64, vec![1.0, 0.0, 0.0, 0.0]),
+            (2, vec![0.9, 0.1, 0.0, 0.0]),
+            (3, vec![0.0, 0.0, 0.0, 1.0]),
+        ];
+        let idx = make_index(&vecs);
+        let results = idx.search(&[1.0, 0.0, 0.0, 0.0], 3);
